//! AI Model client with multi-provider support

use crate::agent::tools::{Tool, ToolExecutor, ToolResult};
use crate::common::{Error, Result};
use crate::config::{AgentConfig, ModelProvider};
use parking_lot::RwLock;
use serde::{Deserialize, Serialize};
use std::sync::Arc;
use tracing::{debug, error, info};

/// Anthropic API request
#[derive(Debug, Serialize)]
struct AnthropicRequest {
    model: String,
    max_tokens: u32,
    messages: Vec<Message>,
    #[serde(skip_serializing_if = "Option::is_none")]
    system: Option<String>,
}

/// Anthropic API message
#[derive(Debug, Serialize, Deserialize, Clone)]
struct Message {
    role: String,
    content: String,
}

/// Anthropic API response
#[derive(Debug, Deserialize)]
#[allow(dead_code)]
struct AnthropicResponse {
    content: Vec<ContentBlock>,
    #[serde(rename = "stop_reason")]
    stop_reason: Option<String>,
    #[serde(rename = "usage")]
    usage: Usage,
}

#[derive(Debug, Deserialize)]
#[allow(dead_code)]
struct ContentBlock {
    #[serde(rename = "type")]
    content_type: String,
    text: Option<String>,
}

#[derive(Debug, Deserialize)]
#[allow(dead_code)]
struct Usage {
    #[serde(rename = "input_tokens")]
    input_tokens: u32,
    #[serde(rename = "output_tokens")]
    output_tokens: u32,
}

/// OpenAI API request
#[derive(Debug, Serialize)]
struct OpenAIRequest {
    model: String,
    messages: Vec<Message>,
    #[serde(skip_serializing_if = "Option::is_none")]
    max_tokens: Option<u32>,
}

/// OpenAI API response
#[derive(Debug, Deserialize)]
#[allow(dead_code)]
struct OpenAIResponse {
    choices: Vec<OpenAIChoice>,
    usage: Option<OpenAIUsage>,
}

#[derive(Debug, Deserialize)]
#[allow(dead_code)]
struct OpenAIChoice {
    message: OpenAIMessage,
}

#[derive(Debug, Deserialize)]
#[allow(dead_code)]
struct OpenAIMessage {
    role: String,
    content: String,
}

#[derive(Debug, Deserialize)]
#[allow(dead_code)]
struct OpenAIUsage {
    #[serde(rename = "prompt_tokens")]
    prompt_tokens: u32,
    #[serde(rename = "completion_tokens")]
    completion_tokens: u32,
}

/// Ollama API request
#[derive(Debug, Serialize)]
struct OllamaRequest {
    model: String,
    prompt: String,
    stream: bool,
}

/// Ollama API response
#[derive(Debug, Deserialize)]
#[allow(dead_code)]
struct OllamaResponse {
    response: String,
}

/// Agent client for AI model interaction
pub struct Agent {
    config: Arc<RwLock<AgentConfig>>,
    http_client: reqwest::Client,
    tool_executor: Arc<ToolExecutor>,
}

impl Agent {
    pub fn new(config: Arc<RwLock<AgentConfig>>) -> Self {
        Self {
            config,
            http_client: reqwest::Client::new(),
            tool_executor: Arc::new(ToolExecutor::new()),
        }
    }

    /// Get list of available tools
    pub fn list_tools(&self) -> Vec<Tool> {
        self.tool_executor.list_tools()
    }

    /// Send a message and get a response (with tool calling loop)
    pub async fn send_message(&self, _session_key: &str, message: &str) -> Result<String> {
        let config = self.config.read().clone();

        // Determine provider based on model name or explicit config
        let provider = config.provider.clone().unwrap_or_else(|| {
            if config.model.starts_with("claude-") || config.model.starts_with("anthropic/") {
                ModelProvider::Anthropic
            } else if config.model.starts_with("gpt-") || config.model.starts_with("openai/") {
                ModelProvider::OpenAI
            } else {
                ModelProvider::Ollama
            }
        });

        // Build messages with initial user message
        let mut messages: Vec<serde_json::Value> = vec![serde_json::json!({
            "role": "user",
            "content": message
        })];

        // Maximum tool call iterations
        let max_turns = 10;
        let tools = self.tool_executor.list_tools();

        for turn in 0..max_turns {
            debug!("Tool loop turn {}", turn + 1);

            match provider {
                ModelProvider::Anthropic => {
                    let response = self.send_anthropic_with_tools(&config, &messages, &tools).await?;

                    // Extract text content
                    let text_content: Option<String> = response["content"]
                        .as_array()
                        .and_then(|arr| {
                            arr.iter()
                                .filter_map(|c| c.get("text").and_then(|t| t.as_str().map(String::from)))
                                .next()
                        });

                    // Check for tool_use in response
                    let tool_calls = response["content"]
                        .as_array()
                        .and_then(|arr| {
                            Some(arr.iter().filter_map(|c| c.get("tool_use").cloned()).collect::<Vec<_>>())
                        })
                        .map(|v| !v.is_empty())
                        .unwrap_or(false);

                    if tool_calls {
                        // Get tool_use blocks
                        let tool_use_blocks = response["content"]
                            .as_array()
                            .unwrap()
                            .iter()
                            .filter(|c| c.get("tool_use").is_some())
                            .filter_map(|c| c.get("tool_use").cloned())
                            .collect::<Vec<_>>();

                        // Add assistant message with tool use
                        messages.push(serde_json::json!({
                            "role": "assistant",
                            "content": tool_use_blocks
                        }));

                        // Execute tools and add results
                        for tool_block in &tool_use_blocks {
                            let tool_name = tool_block["name"].as_str().unwrap_or("");
                            let tool_input = tool_block["input"].clone();
                            let result = self.tool_executor.execute(tool_name, tool_input).await;
                            let result_json = serde_json::to_string(&result).unwrap_or_else(|_| "{}".to_string());
                            messages.push(serde_json::json!({
                                "role": "tool",
                                "content": result_json,
                                "tool_use_id": tool_block["id"]
                            }));
                        }
                    } else {
                        // No tool calls, return the text response
                        return Ok(text_content.unwrap_or_default());
                    }
                }
                ModelProvider::OpenAI => {
                    let response = self.send_openai_with_tools(&config, &messages, &tools).await?;

                    // Check for tool_calls in response
                    let has_tool_calls = response["choices"]
                        .as_array()
                        .and_then(|arr| arr.first())
                        .and_then(|c| c.get("message"))
                        .and_then(|m| m.get("tool_calls"))
                        .is_some();

                    if has_tool_calls {
                        let choices = response["choices"].as_array().unwrap();
                        let message_obj = &choices[0]["message"];

                        // Add assistant message
                        messages.push(message_obj.clone());

                        let tool_calls = message_obj["tool_calls"].as_array().unwrap();

                        // Execute tools and add results
                        for tool_call in tool_calls {
                            let tool_name = tool_call["function"]["name"].as_str().unwrap_or("");
                            let args: serde_json::Value = serde_json::from_str(
                                tool_call["function"]["arguments"].as_str().unwrap_or("{}")
                            ).unwrap_or(serde_json::json!({}));
                            let result = self.tool_executor.execute(tool_name, args).await;
                            let result_json = serde_json::to_string(&result).unwrap_or_else(|_| "{}".to_string());
                            messages.push(serde_json::json!({
                                "role": "tool",
                                "content": result_json,
                                "tool_call_id": tool_call["id"]
                            }));
                        }
                    } else {
                        // No tool calls, return the text response
                        let text = response["choices"]
                            .as_array()
                            .and_then(|arr| arr.first())
                            .and_then(|c| c.get("message"))
                            .and_then(|m| m.get("content"))
                            .and_then(|c| c.as_str())
                            .map(String::from)
                            .unwrap_or_default();
                        return Ok(text);
                    }
                }
                ModelProvider::Ollama => {
                    // Ollama doesn't support tools, just return direct response
                    return self.send_ollama(&config, message).await;
                }
            }
        }

        Ok("Max tool call iterations reached".to_string())
    }

    /// Send message to Anthropic API with tools
    async fn send_anthropic_with_tools(
        &self,
        config: &AgentConfig,
        messages: &[serde_json::Value],
        tools: &[Tool],
    ) -> Result<serde_json::Value> {
        if config.api_key.is_none() {
            return Err(Error::Agent("API key not configured".into()));
        }

        let api_key = config.api_key.clone().unwrap();
        let model = config.model.clone();
        let api_base = config.api_base.clone();

        // Convert tools to Anthropic format
        let anthropic_tools: Vec<serde_json::Value> = tools
            .iter()
            .map(|t| {
                serde_json::json!({
                    "name": t.name,
                    "description": t.description,
                    "input_schema": t.input_schema
                })
            })
            .collect();

        // Build request with tools
        let request = serde_json::json!({
            "model": model,
            "max_tokens": 1024,
            "messages": messages,
            "system": "You are TinyClaw, a helpful AI assistant. You have access to tools to help you answer questions.",
            "tools": anthropic_tools
        });

        // Send request
        let response = self
            .http_client
            .post(format!("{}/v1/messages", api_base))
            .header("x-api-key", api_key)
            .header("anthropic-version", "2023-06-01")
            .header("content-type", "application/json")
            .json(&request)
            .send()
            .await?;

        if !response.status().is_success() {
            let status = response.status();
            let body = response.text().await.unwrap_or_default();
            error!("API error: {} - {}", status, body);
            return Err(Error::Agent(format!("API error: {} - {}", status, body)));
        }

        // Parse response as JSON value
        let response: serde_json::Value = response.json().await?;

        debug!("Anthropic tool response received");

        Ok(response)
    }

    /// Send message to OpenAI API with tools
    async fn send_openai_with_tools(
        &self,
        config: &AgentConfig,
        messages: &[serde_json::Value],
        tools: &[Tool],
    ) -> Result<serde_json::Value> {
        if config.api_key.is_none() {
            return Err(Error::Agent("API key not configured".into()));
        }

        let api_key = config.api_key.clone().unwrap();
        let model = config.model.clone();
        let api_base = config.api_base.clone();

        // Convert tools to OpenAI format
        let openai_tools: Vec<serde_json::Value> = tools
            .iter()
            .map(|t| {
                serde_json::json!({
                    "type": "function",
                    "function": {
                        "name": t.name,
                        "description": t.description,
                        "parameters": t.input_schema
                    }
                })
            })
            .collect();

        // Build request with tools
        let request = serde_json::json!({
            "model": model,
            "messages": messages,
            "max_tokens": 1024,
            "tools": openai_tools
        });

        let response = self
            .http_client
            .post(format!("{}/v1/chat/completions", api_base))
            .header("Authorization", format!("Bearer {}", api_key))
            .header("Content-Type", "application/json")
            .json(&request)
            .send()
            .await?;

        if !response.status().is_success() {
            let status = response.status();
            let body = response.text().await.unwrap_or_default();
            error!("API error: {} - {}", status, body);
            return Err(Error::Agent(format!("API error: {} - {}", status, body)));
        }

        let response: serde_json::Value = response.json().await?;

        debug!("OpenAI tool response received");

        Ok(response)
    }

    /// Send message to Anthropic API
    async fn send_anthropic(&self, config: &AgentConfig, message: &str) -> Result<String> {
        // Check if API key is set
        if config.api_key.is_none() {
            return Err(Error::Agent("API key not configured".into()));
        }

        let api_key = config.api_key.clone().unwrap();
        let model = config.model.clone();
        let api_base = config.api_base.clone();

        info!("Sending message to Anthropic {}: {}", model, message);

        // Build request
        let request = AnthropicRequest {
            model,
            max_tokens: 1024,
            messages: vec![Message {
                role: "user".to_string(),
                content: message.to_string(),
            }],
            system: Some("You are TinyClaw, a helpful AI assistant.".to_string()),
        };

        // Send request
        let response = self
            .http_client
            .post(format!("{}/v1/messages", api_base))
            .header("x-api-key", api_key)
            .header("anthropic-version", "2023-06-01")
            .header("content-type", "application/json")
            .json(&request)
            .send()
            .await?;

        if !response.status().is_success() {
            let status = response.status();
            let body = response.text().await.unwrap_or_default();
            error!("API error: {} - {}", status, body);
            return Err(Error::Agent(format!("API error: {} - {}", status, body)));
        }

        // Parse response
        let response: AnthropicResponse = response.json().await?;

        // Extract text from response
        let text = response
            .content
            .iter()
            .filter_map(|c| c.text.clone())
            .collect::<Vec<_>>()
            .join("");

        debug!("Anthropic response: {}", text);

        Ok(text)
    }

    /// Send message to OpenAI API
    async fn send_openai(&self, config: &AgentConfig, message: &str) -> Result<String> {
        if config.api_key.is_none() {
            return Err(Error::Agent("API key not configured".into()));
        }

        let api_key = config.api_key.clone().unwrap();
        let model = config.model.clone();
        let api_base = config.api_base.clone();

        info!("Sending message to OpenAI {}: {}", model, message);

        let request = OpenAIRequest {
            model,
            messages: vec![Message {
                role: "user".to_string(),
                content: message.to_string(),
            }],
            max_tokens: Some(1024),
        };

        let response = self
            .http_client
            .post(format!("{}/v1/chat/completions", api_base))
            .header("Authorization", format!("Bearer {}", api_key))
            .header("Content-Type", "application/json")
            .json(&request)
            .send()
            .await?;

        if !response.status().is_success() {
            let status = response.status();
            let body = response.text().await.unwrap_or_default();
            error!("API error: {} - {}", status, body);
            return Err(Error::Agent(format!("API error: {} - {}", status, body)));
        }

        let response: OpenAIResponse = response.json().await?;

        let text = response
            .choices
            .first()
            .map(|c| c.message.content.clone())
            .unwrap_or_default();

        debug!("OpenAI response: {}", text);

        Ok(text)
    }

    /// Send message to Ollama API
    async fn send_ollama(&self, config: &AgentConfig, message: &str) -> Result<String> {
        let model = config.model.clone();
        let api_base = config.api_base.clone();

        // For Ollama, default to localhost if no base URL
        let base_url = if api_base.is_empty() || api_base == "https://api.anthropic.com" {
            "http://localhost:11434".to_string()
        } else {
            api_base
        };

        info!("Sending message to Ollama {}: {}", model, message);

        let request = OllamaRequest {
            model,
            prompt: message.to_string(),
            stream: false,
        };

        let response = self
            .http_client
            .post(format!("{}/api/generate", base_url))
            .header("Content-Type", "application/json")
            .json(&request)
            .send()
            .await?;

        if !response.status().is_success() {
            let status = response.status();
            let body = response.text().await.unwrap_or_default();
            error!("API error: {} - {}", status, body);
            return Err(Error::Agent(format!("API error: {} - {}", status, body)));
        }

        let response: OllamaResponse = response.json().await?;

        debug!("Ollama response: {}", response.response);

        Ok(response.response)
    }

    /// Send a message with conversation history
    #[allow(dead_code)]
    pub async fn send_message_with_history(
        &self,
        _session_key: &str,
        message: &str,
        _history: &[(String, String)],
    ) -> Result<String> {
        // For now, just send the message without history
        // History management will be added in later iterations
        self.send_message(_session_key, message).await
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::config::ModelConfig;

    #[test]
    fn test_model_provider_display_name() {
        assert_eq!(ModelProvider::Anthropic.display_name(), "Anthropic");
        assert_eq!(ModelProvider::OpenAI.display_name(), "OpenAI");
        assert_eq!(ModelProvider::Ollama.display_name(), "Ollama");
    }

    #[test]
    fn test_agent_default_config() {
        let agent_config = AgentConfig::default();
        assert_eq!(agent_config.model, "anthropic/claude-sonnet-4-20250514");
        assert_eq!(agent_config.api_base, "https://api.anthropic.com");
        assert!(agent_config.provider.is_none());
    }

    #[test]
    fn test_model_config_default() {
        let model_config = ModelConfig::default();
        assert_eq!(model_config.provider, ModelProvider::Anthropic);
        assert_eq!(model_config.max_tokens, 1024);
    }
}

//! Agent Context Module
//!
//! Manages the context for agent execution including:
//! - Session information
//! - Tool registry
//! - Conversation history
//! - Execution state

use crate::gateway::history::{HistoryManager, Message};
use crate::gateway::session::SessionManager;
use crate::agent::client::Agent;
use crate::agent::tools::ToolExecutor;
use parking_lot::RwLock;
use serde::{Deserialize, Serialize};
use std::sync::Arc;

/// Execution state of the agent
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
#[allow(dead_code)]
pub enum ExecutionState {
    /// Agent is thinking
    Thinking,
    /// Agent is using a tool
    UsingTool { tool: String },
    /// Agent is responding
    Responding,
    /// Agent has finished
    Finished,
    /// Agent encountered an error
    Error,
}

/// Agent context for a single conversation
#[allow(dead_code)]
pub struct AgentContext {
    /// Session ID
    pub session_id: String,
    /// Current execution state
    pub state: RwLock<ExecutionState>,
    /// History manager reference
    pub history_manager: Arc<HistoryManager>,
    /// Session manager reference
    pub session_manager: Arc<SessionManager>,
    /// Tool executor reference
    pub tool_executor: Arc<ToolExecutor>,
    /// Agent client reference
    pub agent: Arc<Agent>,
    /// Maximum turns in a loop
    pub max_turns: usize,
    /// Current turn count
    pub turn_count: RwLock<usize>,
}

#[allow(dead_code)]
impl AgentContext {
    /// Create a new agent context
    #[allow(dead_code)]
    pub fn new(
        session_id: String,
        history_manager: Arc<HistoryManager>,
        session_manager: Arc<SessionManager>,
        tool_executor: Arc<ToolExecutor>,
        agent: Arc<Agent>,
    ) -> Self {
        Self {
            session_id,
            state: RwLock::new(ExecutionState::Thinking),
            history_manager,
            session_manager,
            tool_executor,
            agent,
            max_turns: 10,
            turn_count: RwLock::new(0),
        }
    }

    /// Get current state
    pub fn get_state(&self) -> ExecutionState {
        self.state.read().clone()
    }

    /// Set state
    pub fn set_state(&self, new_state: ExecutionState) {
        *self.state.write() = new_state;
    }

    /// Increment turn count
    pub fn increment_turn(&self) {
        let mut count = self.turn_count.write();
        *count += 1;
    }

    /// Check if max turns reached
    pub fn max_turns_reached(&self) -> bool {
        *self.turn_count.read() >= self.max_turns
    }

    /// Reset turn count
    pub fn reset_turns(&self) {
        *self.turn_count.write() = 0;
    }

    /// Add user message to history
    pub fn add_user_message(&self, content: &str) {
        self.history_manager.add_message(
            &self.session_id,
            Message::user(content),
        );
    }

    /// Add assistant message to history
    pub fn add_assistant_message(&self, content: &str) {
        self.history_manager.add_message(
            &self.session_id,
            Message::assistant(content),
        );
    }

    /// Get conversation history
    pub fn get_history(&self) -> Vec<Message> {
        if let Some(history) = self.history_manager.get(&self.session_id) {
            history.read().get_messages().to_vec()
        } else {
            Vec::new()
        }
    }
}

//! Agent module - AI model client and tool execution

pub mod client;
pub mod context;
pub mod runtime;
pub mod tools;

pub use client::Agent;

//! Agent Runtime Module
//!
//! Core runtime for agent execution with tool calling loop.

use crate::agent::client::Agent;
use crate::agent::context::{AgentContext, ExecutionState};
use crate::agent::tools::{ToolExecutor, ToolResult};
use crate::common::Result;
use crate::gateway::events::{Event, EventEmitter};
use crate::gateway::history::HistoryManager;
use crate::gateway::session::SessionManager;
use parking_lot::RwLock;
use serde::{Deserialize, Serialize};
use std::sync::Arc;
use tracing::{info, warn};

/// Tool call from the model
#[derive(Debug, Clone, Serialize, Deserialize)]
#[allow(dead_code)]
pub struct ToolCall {
    /// Unique ID for the tool call
    pub id: String,
    /// Name of the tool to call
    pub name: String,
    /// Arguments to the tool (JSON)
    pub arguments: serde_json::Value,
}

/// Response from the model
#[derive(Debug, Clone, Serialize, Deserialize)]
#[allow(dead_code)]
pub struct ModelResponse {
    /// Text content from the model
    #[serde(skip_serializing_if = "Option::is_none")]
    pub text: Option<String>,
    /// Tool calls requested by the model
    #[serde(skip_serializing_if = "Option::is_none")]
    pub tool_calls: Option<Vec<ToolCall>>,
    /// Whether the conversation is complete
    pub stop_reason: Option<String>,
}

/// Agent runtime configuration
#[derive(Debug, Clone)]
#[allow(dead_code)]
pub struct RuntimeConfig {
    /// Maximum turns in tool loop
    pub max_turns: usize,
    /// Whether to emit events
    pub emit_events: bool,
    /// Tool call timeout in seconds
    pub tool_timeout_secs: u64,
}

impl Default for RuntimeConfig {
    fn default() -> Self {
        Self {
            max_turns: 10,
            emit_events: true,
            tool_timeout_secs: 30,
        }
    }
}

/// Agent runtime for executing agent loops
#[allow(dead_code)]
pub struct AgentRuntime {
    config: RwLock<RuntimeConfig>,
    tool_executor: Arc<ToolExecutor>,
    event_emitter: Option<Arc<EventEmitter>>,
}

#[allow(dead_code)]
impl AgentRuntime {
    /// Create a new agent runtime
    pub fn new(tool_executor: Arc<ToolExecutor>) -> Self {
        Self {
            config: RwLock::new(RuntimeConfig::default()),
            tool_executor,
            event_emitter: None,
        }
    }

    /// Set the event emitter
    pub fn with_event_emitter(mut self, emitter: Arc<EventEmitter>) -> Self {
        self.event_emitter = Some(emitter);
        self
    }

    /// Update configuration
    pub fn set_config(&self, config: RuntimeConfig) {
        *self.config.write() = config;
    }

    /// Get configuration
    pub fn get_config(&self) -> RuntimeConfig {
        self.config.read().clone()
    }

    /// Execute a complete agent turn with tool calling loop
    pub async fn run_turn(
        &self,
        context: &AgentContext,
        user_message: &str,
    ) -> Result<String> {
        info!("Starting agent turn for session: {}", context.session_id);

        // Reset state
        context.reset_turns();
        context.set_state(ExecutionState::Thinking);

        // Add user message to history
        context.add_user_message(user_message);

        // Main tool calling loop
        loop {
            context.increment_turn();

            if context.max_turns_reached() {
                warn!("Max turns reached, stopping loop");
                context.set_state(ExecutionState::Finished);
                return Ok("Maximum turns reached. I need to stop here.".to_string());
            }

            // Get response from model
            context.set_state(ExecutionState::Thinking);
            let response = self.get_model_response(context).await?;

            // Check if we have text to return
            if let Some(text) = &response.text {
                if text.is_empty() {
                    // No text, check for tool calls
                    if let Some(tool_calls) = &response.tool_calls {
                        if tool_calls.is_empty() {
                            // Empty response with no tools, we're done
                            context.set_state(ExecutionState::Finished);
                            return Ok(text.clone());
                        }
                    }
                } else {
                    // Has text, check if we should stop
                    if response.stop_reason.as_deref() == Some("end_turn") {
                        context.add_assistant_message(text);
                        context.set_state(ExecutionState::Finished);

                        // Emit event
                        if self.config.read().emit_events {
                            if let Some(emitter) = &self.event_emitter {
                                emitter.emit(Event::AssistantText {
                                    session_id: context.session_id.clone(),
                                    text: text.clone(),
                                });
                            }
                        }

                        return Ok(text.clone());
                    }
                }
            }

            // Process tool calls
            if let Some(tool_calls) = &response.tool_calls {
                for tool_call in tool_calls {
                    context.set_state(ExecutionState::UsingTool { 
                        tool: tool_call.name.clone() 
                    });

                    // Emit tool use event
                    if self.config.read().emit_events {
                        if let Some(emitter) = &self.event_emitter {
                            emitter.emit(Event::AssistantToolUse {
                                session_id: context.session_id.clone(),
                                tool: tool_call.name.clone(),
                                input: tool_call.arguments.clone(),
                            });
                        }
                    }

                    // Execute tool
                    let result = self.execute_tool(&tool_call.name, &tool_call.arguments).await;

                    // Add tool result to history
                    let tool_result_str = match &result {
                        Ok(r) => r.output.clone(),
                        Err(e) => e.to_string(),
                    };

                    context.history_manager.add_message(
                        &context.session_id,
                        crate::gateway::history::Message::tool(
                            &tool_result_str,
                            &tool_call.id,
                            &tool_call.name,
                        ),
                    );

                    // Emit tool result event
                    if self.config.read().emit_events {
                        if let Some(emitter) = &self.event_emitter {
                            emitter.emit(Event::ToolResult {
                                session_id: context.session_id.clone(),
                                tool_call_id: tool_call.id.clone(),
                                output: tool_result_str,
                            });
                        }
                    }
                }
            } else {
                // No tool calls and no text, we're done
                if response.text.is_none() || response.text.as_ref().map(|s| s.is_empty()).unwrap_or(true) {
                    context.set_state(ExecutionState::Finished);
                    return Ok("I don't have anything more to say.".to_string());
                }
            }
        }
    }

    /// Get response from the model
    async fn get_model_response(&self, context: &AgentContext) -> Result<ModelResponse> {
        // For now, just call the agent directly
        // In a full implementation, this would format the conversation history
        // and parse tool calls from the response

        let history = context.get_history();
        let last_message = history.last()
            .map(|m| m.content.clone())
            .unwrap_or_default();

        let response_text = context.agent.send_message(&context.session_id, &last_message).await?;

        Ok(ModelResponse {
            text: Some(response_text),
            tool_calls: None,
            stop_reason: Some("end_turn".to_string()),
        })
    }

    /// Execute a tool
    async fn execute_tool(&self, tool_name: &str, arguments: &serde_json::Value) -> Result<ToolResult> {
        info!("Executing tool: {} with args: {:?}", tool_name, arguments);

        // Add any required fields to arguments
        let args = arguments.clone();

        let result = self.tool_executor.execute(tool_name, args).await;

        if !result.success {
            warn!("Tool {} failed: {:?}", tool_name, result.error);
        }

        Ok(result)
    }

    /// Create an agent context for a session
    pub fn create_context(
        &self,
        session_id: String,
        history_manager: Arc<HistoryManager>,
        session_manager: Arc<SessionManager>,
        agent: Arc<Agent>,
    ) -> AgentContext {
        AgentContext::new(
            session_id,
            history_manager,
            session_manager,
            Arc::new(ToolExecutor::new()),
            agent,
        )
    }
}

impl Default for AgentRuntime {
    fn default() -> Self {
        Self::new(Arc::new(ToolExecutor::new()))
    }
}

//! Advanced tools module

use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use tokio::fs;
use tracing::info;

/// Tool definition
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Tool {
    pub name: String,
    pub description: String,
    pub input_schema: serde_json::Value,
}

/// Tool execution result
#[derive(Debug, Serialize, Deserialize)]
pub struct ToolResult {
    pub success: bool,
    pub output: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub error: Option<String>,
}

/// Tool executor
#[derive(Default)]
pub struct ToolExecutor {
    tools: HashMap<String, Tool>,
}

impl ToolExecutor {
    pub fn new() -> Self {
        let mut tools = HashMap::new();

        // Register exec tool
        tools.insert(
            "exec".to_string(),
            Tool {
                name: "exec".to_string(),
                description: "Execute a shell command".to_string(),
                input_schema: serde_json::json!({
                    "type": "object",
                    "properties": {
                        "command": {
                            "type": "string",
                            "description": "The command to execute"
                        },
                        "timeout": {
                            "type": "number",
                            "description": "Timeout in milliseconds"
                        }
                    },
                    "required": ["command"]
                }),
            },
        );

        // Register read_file tool
        tools.insert(
            "read_file".to_string(),
            Tool {
                name: "read_file".to_string(),
                description: "Read contents of a file".to_string(),
                input_schema: serde_json::json!({
                    "type": "object",
                    "properties": {
                        "path": {
                            "type": "string",
                            "description": "Path to the file to read"
                        },
                        "max_bytes": {
                            "type": "number",
                            "description": "Maximum bytes to read"
                        }
                    },
                    "required": ["path"]
                }),
            },
        );

        // Register write_file tool
        tools.insert(
            "write_file".to_string(),
            Tool {
                name: "write_file".to_string(),
                description: "Write content to a file".to_string(),
                input_schema: serde_json::json!({
                    "type": "object",
                    "properties": {
                        "path": {
                            "type": "string",
                            "description": "Path to the file to write"
                        },
                        "content": {
                            "type": "string",
                            "description": "Content to write"
                        }
                    },
                    "required": ["path", "content"]
                }),
            },
        );

        // Register list_dir tool
        tools.insert(
            "list_dir".to_string(),
            Tool {
                name: "list_dir".to_string(),
                description: "List contents of a directory".to_string(),
                input_schema: serde_json::json!({
                    "type": "object",
                    "properties": {
                        "path": {
                            "type": "string",
                            "description": "Path to the directory"
                        }
                    },
                    "required": ["path"]
                }),
            },
        );

        // Register http_request tool
        tools.insert(
            "http_request".to_string(),
            Tool {
                name: "http_request".to_string(),
                description: "Make an HTTP request".to_string(),
                input_schema: serde_json::json!({
                    "type": "object",
                    "properties": {
                        "url": {
                            "type": "string",
                            "description": "URL to request"
                        },
                        "method": {
                            "type": "string",
                            "description": "HTTP method (GET, POST, etc.)"
                        },
                        "headers": {
                            "type": "object",
                            "description": "Request headers"
                        },
                        "body": {
                            "type": "string",
                            "description": "Request body"
                        }
                    },
                    "required": ["url"]
                }),
            },
        );

        Self { tools }
    }

    /// List all available tools
    pub fn list_tools(&self) -> Vec<Tool> {
        self.tools.values().cloned().collect()
    }

    /// Get a tool by name
    #[allow(dead_code)]
    pub fn get_tool(&self, name: &str) -> Option<&Tool> {
        self.tools.get(name)
    }

    /// Execute a tool
    pub async fn execute(&self, name: &str, input: serde_json::Value) -> ToolResult {
        match name {
            "exec" => self.execute_exec(input).await,
            "read_file" => self.execute_read_file(input).await,
            "write_file" => self.execute_write_file(input).await,
            "list_dir" => self.execute_list_dir(input).await,
            "http_request" => self.execute_http_request(input).await,
            _ => ToolResult {
                success: false,
                output: String::new(),
                error: Some(format!("Unknown tool: {}", name)),
            },
        }
    }

    /// Execute the exec tool
    async fn execute_exec(&self, input: serde_json::Value) -> ToolResult {
        let command = input
            .get("command")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        if command.is_empty() {
            return ToolResult {
                success: false,
                output: String::new(),
                error: Some("command is required".to_string()),
            };
        }

        info!("Executing command: {}", command);

        let output = tokio::process::Command::new("sh")
            .arg("-c")
            .arg(command)
            .output()
            .await;

        match output {
            Ok(output) => {
                let stdout = String::from_utf8_lossy(&output.stdout).to_string();
                let stderr = String::from_utf8_lossy(&output.stderr).to_string();

                ToolResult {
                    success: output.status.success(),
                    output: stdout,
                    error: if stderr.is_empty() {
                        None
                    } else {
                        Some(stderr)
                    },
                }
            }
            Err(e) => ToolResult {
                success: false,
                output: String::new(),
                error: Some(e.to_string()),
            },
        }
    }

    /// Execute the read_file tool
    async fn execute_read_file(&self, input: serde_json::Value) -> ToolResult {
        let path = input
            .get("path")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        if path.is_empty() {
            return ToolResult {
                success: false,
                output: String::new(),
                error: Some("path is required".to_string()),
            };
        }

        info!("Reading file: {}", path);

        match fs::read_to_string(path).await {
            Ok(content) => ToolResult {
                success: true,
                output: content,
                error: None,
            },
            Err(e) => ToolResult {
                success: false,
                output: String::new(),
                error: Some(e.to_string()),
            },
        }
    }

    /// Execute the write_file tool
    async fn execute_write_file(&self, input: serde_json::Value) -> ToolResult {
        let path = input
            .get("path")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        let content = input
            .get("content")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        if path.is_empty() {
            return ToolResult {
                success: false,
                output: String::new(),
                error: Some("path is required".to_string()),
            };
        }

        info!("Writing file: {}", path);

        match fs::write(path, content).await {
            Ok(()) => ToolResult {
                success: true,
                output: format!("File written successfully: {}", path),
                error: None,
            },
            Err(e) => ToolResult {
                success: false,
                output: String::new(),
                error: Some(e.to_string()),
            },
        }
    }

    /// Execute the list_dir tool
    async fn execute_list_dir(&self, input: serde_json::Value) -> ToolResult {
        let path = input
            .get("path")
            .and_then(|v| v.as_str())
            .unwrap_or(".");

        info!("Listing directory: {}", path);

        match fs::read_dir(path).await {
            Ok(mut entries) => {
                let mut results = Vec::new();
                while let Some(entry) = entries.next_entry().await.unwrap_or(None) {
                    let file_name = entry.file_name().to_string_lossy().to_string();
                    let file_type = entry.file_type().await.map(|ft| {
                        if ft.is_dir() {
                            "dir"
                        } else if ft.is_file() {
                            "file"
                        } else if ft.is_symlink() {
                            "symlink"
                        } else {
                            "unknown"
                        }
                    }).unwrap_or("unknown");

                    results.push(format!("{} ({})", file_name, file_type));
                }

                ToolResult {
                    success: true,
                    output: results.join("\n"),
                    error: None,
                }
            }
            Err(e) => ToolResult {
                success: false,
                output: String::new(),
                error: Some(e.to_string()),
            },
        }
    }

    /// Execute the http_request tool
    async fn execute_http_request(&self, input: serde_json::Value) -> ToolResult {
        let url = input
            .get("url")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        if url.is_empty() {
            return ToolResult {
                success: false,
                output: String::new(),
                error: Some("url is required".to_string()),
            };
        }

        let method = input
            .get("method")
            .and_then(|v| v.as_str())
            .unwrap_or("GET")
            .to_uppercase();

        info!("Making HTTP {} request to: {}", method, url);

        let client = reqwest::Client::new();

        let request_builder = match method.as_str() {
            "GET" => client.get(url),
            "POST" => client.post(url),
            "PUT" => client.put(url),
            "DELETE" => client.delete(url),
            "PATCH" => client.patch(url),
            _ => {
                return ToolResult {
                    success: false,
                    output: String::new(),
                    error: Some(format!("Unsupported method: {}", method)),
                };
            }
        };

        // Add headers if provided
        if let Some(headers) = input.get("headers").and_then(|v| v.as_object()) {
            for (_key, value) in headers {
                if let Some(_value_str) = value.as_str() {
                    // Skip invalid headers
                }
            }
        }

        // Add body if provided
        let request_builder = if let Some(body) = input.get("body").and_then(|v| v.as_str()) {
            request_builder.body(body.to_string())
        } else {
            request_builder
        };

        match request_builder.send().await {
            Ok(response) => {
                let status = response.status().as_u16();
                let success = response.status().is_success();
                let body = response.text().await.unwrap_or_default();

                ToolResult {
                    success,
                    output: format!("Status: {}\n\n{}", status, body),
                    error: None,
                }
            }
            Err(e) => ToolResult {
                success: false,
                output: String::new(),
                error: Some(e.to_string()),
            },
        }
    }
}

