//! Authentication and authorization

use crate::common::error::{Error, Result};
use serde::{Deserialize, Serialize};

/// API Key authentication
#[derive(Debug, Clone, Serialize, Deserialize)]
#[allow(dead_code)]
pub struct ApiKey {
    pub id: String,
    pub key: String,
    pub name: String,
    pub permissions: Vec<Permission>,
    pub created_at: chrono::DateTime<chrono::Utc>,
    pub expires_at: Option<chrono::DateTime<chrono::Utc>>,
    pub enabled: bool,
}

/// Permission types
#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[allow(dead_code)]
pub enum Permission {
    Read,
    Write,
    Admin,
    Execute,
}

#[allow(dead_code)]
impl ApiKey {
    pub fn new(id: impl Into<String>, key: impl Into<String>, name: impl Into<String>) -> Self {
        Self {
            id: id.into(),
            key: key.into(),
            name: name.into(),
            permissions: vec![Permission::Read, Permission::Write],
            created_at: chrono::Utc::now(),
            expires_at: None,
            enabled: true,
        }
    }

    pub fn with_permissions(mut self, permissions: Vec<Permission>) -> Self {
        self.permissions = permissions;
        self
    }

    pub fn with_expiry(mut self, expires_at: chrono::DateTime<chrono::Utc>) -> Self {
        self.expires_at = Some(expires_at);
        self
    }

    pub fn is_valid(&self) -> bool {
        self.enabled && self.expires_at.is_none_or(|exp| exp > chrono::Utc::now())
    }

    pub fn has_permission(&self, permission: &Permission) -> bool {
        self.permissions.contains(permission)
    }
}

/// Authenticator
#[allow(dead_code)]
pub struct Authenticator {
    keys: std::collections::HashMap<String, ApiKey>,
}

#[allow(dead_code)]
impl Authenticator {
    pub fn new() -> Self {
        Self {
            keys: std::collections::HashMap::new(),
        }
    }

    /// Add an API key
    pub fn add_key(&mut self, api_key: ApiKey) {
        self.keys.insert(api_key.key.clone(), api_key);
    }

    /// Remove an API key
    pub fn remove_key(&mut self, key: &str) -> Option<ApiKey> {
        self.keys.remove(key)
    }

    /// Validate a key
    pub fn validate(&self, key: &str) -> Option<&ApiKey> {
        self.keys.get(key).filter(|k| k.is_valid())
    }

    /// List all keys (without secret)
    pub fn list_keys(&self) -> Vec<serde_json::Value> {
        self.keys.values()
            .map(|k| {
                serde_json::json!({
                    "id": k.id,
                    "name": k.name,
                    "permissions": k.permissions,
                    "createdAt": k.created_at.to_rfc3339(),
                    "expiresAt": k.expires_at.map(|e| e.to_rfc3339()),
                    "enabled": k.enabled,
                })
            })
            .collect()
    }
}

impl Default for Authenticator {
    fn default() -> Self {
        Self::new()
    }
}

/// Authorization helper
#[allow(dead_code)]
pub fn require_admin(api_key: &ApiKey) -> Result<()> {
    if api_key.has_permission(&Permission::Admin) {
        Ok(())
    } else {
        Err(Error::Auth("Admin permission required".into()))
    }
}

#[allow(dead_code)]
pub fn require_permission(api_key: &ApiKey, permission: Permission) -> Result<()> {
    if api_key.has_permission(&permission) {
        Ok(())
    } else {
        Err(Error::Auth(format!("Permission {:?} required", permission)))
    }
}

//! Event system module

use serde::{Deserialize, Serialize};
use tokio::sync::broadcast;

/// Event types
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(tag = "type", content = "data")]
pub enum Event {
    /// Assistant sent text
    #[serde(rename = "assistant.text")]
    AssistantText {
        session_id: String,
        text: String,
    },

    /// Assistant used a tool
    #[serde(rename = "assistant.tool_use")]
    AssistantToolUse {
        session_id: String,
        tool: String,
        input: serde_json::Value,
    },

    /// Tool result
    #[serde(rename = "tool_result")]
    ToolResult {
        session_id: String,
        tool_call_id: String,
        output: String,
    },

    /// Session created
    #[serde(rename = "session.created")]
    SessionCreated {
        session_id: String,
        kind: String,
    },

    /// Session ended
    #[serde(rename = "session.ended")]
    SessionEnded {
        session_id: String,
    },

    /// Error occurred
    #[serde(rename = "error")]
    Error {
        session_id: String,
        message: String,
    },

    /// Status update
    #[serde(rename = "status")]
    Status {
        message: String,
    },
}

/// Event emitter for broadcasting events
pub struct EventEmitter {
    sender: broadcast::Sender<Event>,
}

impl EventEmitter {
    pub fn new() -> Self {
        let (sender, _) = broadcast::channel(100);
        Self { sender }
    }

    /// Emit an event
    pub fn emit(&self, event: Event) {
        let _ = self.sender.send(event);
    }

    /// Subscribe to events
    #[allow(dead_code)]
    pub fn subscribe(&self) -> broadcast::Receiver<Event> {
        self.sender.subscribe()
    }

    /// Get subscriber count
    #[allow(dead_code)]
    pub fn subscriber_count(&self) -> usize {
        self.sender.receiver_count()
    }
}

impl Default for EventEmitter {
    fn default() -> Self {
        Self::new()
    }
}

//! Session history module

use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::sync::Arc;
use parking_lot::RwLock;
use uuid::Uuid;

/// Message role
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
pub enum Role {
    #[serde(rename = "user")]
    User,
    #[serde(rename = "assistant")]
    Assistant,
    #[serde(rename = "system")]
    System,
    #[serde(rename = "tool")]
    Tool,
}

/// A message in the conversation history
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Message {
    pub id: String,
    pub role: Role,
    pub content: String,
    pub timestamp: DateTime<Utc>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub tool_call_id: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub tool_name: Option<String>,
}

impl Message {
    pub fn user(content: impl Into<String>) -> Self {
        Self {
            id: Uuid::new_v4().to_string(),
            role: Role::User,
            content: content.into(),
            timestamp: Utc::now(),
            tool_call_id: None,
            tool_name: None,
        }
    }

    pub fn assistant(content: impl Into<String>) -> Self {
        Self {
            id: Uuid::new_v4().to_string(),
            role: Role::Assistant,
            content: content.into(),
            timestamp: Utc::now(),
            tool_call_id: None,
            tool_name: None,
        }
    }

    #[allow(dead_code)]
    pub fn system(content: impl Into<String>) -> Self {
        Self {
            id: Uuid::new_v4().to_string(),
            role: Role::System,
            content: content.into(),
            timestamp: Utc::now(),
            tool_call_id: None,
            tool_name: None,
        }
    }

    #[allow(dead_code)]
    pub fn tool(content: impl Into<String>, tool_call_id: impl Into<String>, tool_name: impl Into<String>) -> Self {
        Self {
            id: Uuid::new_v4().to_string(),
            role: Role::Tool,
            content: content.into(),
            timestamp: Utc::now(),
            tool_call_id: Some(tool_call_id.into()),
            tool_name: Some(tool_name.into()),
        }
    }
}

/// Session history
#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct SessionHistory {
    pub session_id: String,
    pub messages: Vec<Message>,
    pub created_at: DateTime<Utc>,
    pub updated_at: DateTime<Utc>,
}

impl SessionHistory {
    pub fn new(session_id: impl Into<String>) -> Self {
        let now = Utc::now();
        Self {
            session_id: session_id.into(),
            messages: Vec::new(),
            created_at: now,
            updated_at: now,
        }
    }

    pub fn add_message(&mut self, message: Message) {
        self.updated_at = Utc::now();
        self.messages.push(message);
    }

    #[allow(dead_code)]
    pub fn get_messages(&self) -> &[Message] {
        &self.messages
    }

    #[allow(dead_code)]
    pub fn clear(&mut self) {
        self.messages.clear();
        self.updated_at = Utc::now();
    }

    #[allow(dead_code)]
    pub fn len(&self) -> usize {
        self.messages.len()
    }

    #[allow(dead_code)]
    pub fn is_empty(&self) -> bool {
        self.messages.is_empty()
    }
}

/// History manager
pub struct HistoryManager {
    histories: RwLock<HashMap<String, Arc<RwLock<SessionHistory>>>>,
}

impl HistoryManager {
    pub fn new() -> Self {
        Self {
            histories: RwLock::new(HashMap::new()),
        }
    }

    /// Get or create history for a session
    pub fn get_or_create(&self, session_id: &str) -> Arc<RwLock<SessionHistory>> {
        let mut histories = self.histories.write();
        if let Some(history) = histories.get(session_id) {
            return history.clone();
        }

        let history = Arc::new(RwLock::new(SessionHistory::new(session_id)));
        histories.insert(session_id.to_string(), history.clone());
        history
    }

    /// Add a message to a session's history
    pub fn add_message(&self, session_id: &str, message: Message) {
        let history = self.get_or_create(session_id);
        history.write().add_message(message);
    }

    /// Get history for a session
    pub fn get(&self, session_id: &str) -> Option<Arc<RwLock<SessionHistory>>> {
        self.histories.read().get(session_id).cloned()
    }

    /// List all histories
    #[allow(dead_code)]
    pub fn list(&self) -> Vec<Arc<RwLock<SessionHistory>>> {
        self.histories.read().values().cloned().collect()
    }

    /// Clear history for a session
    #[allow(dead_code)]
    pub fn clear(&self, session_id: &str) {
        if let Some(history) = self.histories.read().get(session_id) {
            history.write().clear();
        }
    }

    /// Remove history for a session
    #[allow(dead_code)]
    pub fn remove(&self, session_id: &str) {
        self.histories.write().remove(session_id);
    }
}

impl Default for HistoryManager {
    fn default() -> Self {
        Self::new()
    }
}

