//! Persistence module for session data
//!
//! Provides simple JSON-based persistence for sessions and messages.

use crate::gateway::history::{Message, SessionHistory};
use anyhow::Result;
use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use std::path::PathBuf;
use tokio::fs;

/// Persistent storage for a session
#[derive(Debug, Clone, Serialize, Deserialize)]
#[allow(dead_code)]
pub struct SessionStore {
    pub session_id: String,
    pub messages: Vec<Message>,
    pub created_at: DateTime<Utc>,
    pub updated_at: DateTime<Utc>,
}

impl From<&SessionHistory> for SessionStore {
    fn from(history: &SessionHistory) -> Self {
        Self {
            session_id: history.session_id.clone(),
            messages: history.messages.clone(),
            created_at: history.created_at,
            updated_at: history.updated_at,
        }
    }
}

/// Persistence manager
#[allow(dead_code)]
pub struct PersistenceManager {
    data_dir: PathBuf,
}

#[allow(dead_code)]
impl PersistenceManager {
    /// Create a new persistence manager
    pub fn new(data_dir: PathBuf) -> Self {
        Self { data_dir }
    }

    /// Ensure data directory exists
    pub async fn ensure_dir(&self) -> Result<()> {
        fs::create_dir_all(&self.data_dir).await?;
        fs::create_dir_all(self.data_dir.join("sessions")).await?;
        Ok(())
    }

    /// Save a session to disk
    pub async fn save_session(&self, history: &SessionHistory) -> Result<()> {
        self.ensure_dir().await?;

        let store = SessionStore::from(history);
        let path = self.data_dir.join("sessions").join(format!("{}.json", history.session_id));
        let json = serde_json::to_string_pretty(&store)?;
        fs::write(path, json).await?;

        Ok(())
    }

    /// Load a session from disk
    pub async fn load_session(&self, session_id: &str) -> Result<Option<SessionHistory>> {
        let path = self.data_dir.join("sessions").join(format!("{}.json", session_id));

        if !path.exists() {
            return Ok(None);
        }

        let json = fs::read_to_string(path).await?;
        let store: SessionStore = serde_json::from_str(&json)?;

        let mut history = SessionHistory::new(store.session_id);
        history.messages = store.messages;
        // Note: We don't restore created_at and updated_at exactly
        // since SessionHistory doesn't expose setters

        Ok(Some(history))
    }

    /// List all persisted session IDs
    pub async fn list_sessions(&self) -> Result<Vec<String>> {
        let sessions_dir = self.data_dir.join("sessions");

        if !sessions_dir.exists() {
            return Ok(Vec::new());
        }

        let mut entries = fs::read_dir(sessions_dir).await?;
        let mut session_ids = Vec::new();

        while let Some(entry) = entries.next_entry().await? {
            let path = entry.path();
            if path.extension().and_then(|s| s.to_str()) == Some("json") {
                if let Some(stem) = path.file_stem().and_then(|s| s.to_str()) {
                    session_ids.push(stem.to_string());
                }
            }
        }

        Ok(session_ids)
    }

    /// Delete a session from disk
    pub async fn delete_session(&self, session_id: &str) -> Result<()> {
        let path = self.data_dir.join("sessions").join(format!("{}.json", session_id));

        if path.exists() {
            fs::remove_file(path).await?;
        }

        Ok(())
    }
}

impl Default for PersistenceManager {
    fn default() -> Self {
        let data_dir = dirs::data_local_dir()
            .unwrap_or_else(|| PathBuf::from("."))
            .join("tiny_claw");

        Self::new(data_dir)
    }
}

//! Protocol definitions

use serde::{Deserialize, Serialize};

/// Request message from client
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(untagged)]
pub enum Request {
    /// Standard request with id, method, params
    Standard(RequestStandard),
    /// Notification (no id, no response)
    Notification(RequestNotification),
}

impl Request {
    pub fn method(&self) -> &str {
        match self {
            Request::Standard(r) => &r.method,
            Request::Notification(r) => &r.method,
        }
    }

    pub fn id(&self) -> Option<&str> {
        match self {
            Request::Standard(r) => r.id.as_deref(),
            Request::Notification(_) => None,
        }
    }

    pub fn params(&self) -> &serde_json::Value {
        match self {
            Request::Standard(r) => &r.params,
            Request::Notification(r) => &r.params,
        }
    }
}

/// Standard request with id
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RequestStandard {
    pub id: Option<String>,
    pub method: String,
    pub params: serde_json::Value,
}

/// Notification (no response expected)
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RequestNotification {
    pub method: String,
    pub params: serde_json::Value,
}

/// Response message to client
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(untagged)]
pub enum Response {
    /// Success response
    Success(ResponseSuccess),
    /// Error response
    Error(ResponseError),
    /// Notification (no id)
    Notification(ResponseNotification),
}

/// Success response
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ResponseSuccess {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub id: Option<String>,
    pub result: serde_json::Value,
}

/// Error response
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ResponseError {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub id: Option<String>,
    pub error: ResponseErrorBody,
}

/// Error body
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ResponseErrorBody {
    pub code: String,
    pub message: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub data: Option<serde_json::Value>,
}

/// Notification response (no id)
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ResponseNotification {
    pub method: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub params: Option<serde_json::Value>,
}

impl ResponseSuccess {
    pub fn new(id: Option<String>, result: serde_json::Value) -> Self {
        Self { id, result }
    }
}

impl ResponseError {
    pub fn new(id: Option<String>, code: impl Into<String>, message: impl Into<String>) -> Self {
        Self {
            id,
            error: ResponseErrorBody {
                code: code.into(),
                message: message.into(),
                data: None,
            },
        }
    }

    #[allow(dead_code)]
    pub fn with_data(
        id: Option<String>,
        code: impl Into<String>,
        message: impl Into<String>,
        data: serde_json::Value,
    ) -> Self {
        Self {
            id,
            error: ResponseErrorBody {
                code: code.into(),
                message: message.into(),
                data: Some(data),
            },
        }
    }
}

impl From<ResponseSuccess> for Response {
    fn from(r: ResponseSuccess) -> Self {
        Response::Success(r)
    }
}

impl From<ResponseError> for Response {
    fn from(r: ResponseError) -> Self {
        Response::Error(r)
    }
}

