//! WebSocket server

use crate::common::Result;
use crate::config::Config;
use crate::gateway::messages::handle_request;
use crate::gateway::protocol::*;
use futures_util::{SinkExt, StreamExt};
use parking_lot::RwLock;
use std::sync::Arc;
use tokio::net::{TcpListener, TcpStream};
use tokio::sync::broadcast;
use tokio::sync::mpsc;
use tokio_tungstenite::accept_async;
use tokio_tungstenite::tungstenite::Message;
use tracing::{debug, error, info, warn};

/// Maximum concurrent requests per connection
const MAX_CONCURRENT_REQUESTS: usize = 10;

/// Start the WebSocket server
pub async fn start_server(
    config: Arc<RwLock<Config>>,
    ctx: crate::gateway::messages::HandlerContext,
    shutdown_rx: broadcast::Receiver<()>,
) -> Result<()> {
    let addr = config.read().gateway.bind.clone();
    let listener = TcpListener::bind(&addr).await?;

    info!("Gateway listening on ws://{}", addr);

    let mut shutdown_rx = shutdown_rx;

    loop {
        tokio::select! {
            result = listener.accept() => {
                match result {
                    Ok((stream, _addr)) => {
                        let ctx = crate::gateway::messages::HandlerContext::new(
                            ctx.session_manager.clone(),
                            ctx.history_manager.clone(),
                            ctx.event_emitter.clone(),
                            ctx.config.clone(),
                            ctx.agent.clone(),
                            ctx.shutdown_tx.clone(),
                        );
                        tokio::spawn(handle_connection(stream, ctx));
                    }
                    Err(e) => {
                        error!("Failed to accept connection: {}", e);
                    }
                }
            }
            _ = shutdown_rx.recv() => {
                info!("Server shutting down");
                break;
            }
        }
    }

    Ok(())
}

/// Internal message for the connection handler
enum ConnectionMessage {
    /// A text message from the client
    Text(String),
    /// Ping received
    Ping(Vec<u8>),
    /// Connection closed
    Close,
    /// WebSocket error
    Error(()),
}

/// Handle a single WebSocket connection with message queue
async fn handle_connection(stream: TcpStream, ctx: crate::gateway::messages::HandlerContext) {
    let addr = stream.peer_addr().unwrap_or_else(|_| "unknown".parse().unwrap());
    info!("New connection from: {}", addr);

    let ws_stream = match accept_async(stream).await {
        Ok(ws) => ws,
        Err(e) => {
            error!("WebSocket handshake failed: {}", e);
            return;
        }
    };

    let (mut write, mut read) = ws_stream.split();

    // Create a channel for message processing
    let (msg_tx, mut msg_rx) = mpsc::channel::<ConnectionMessage>(MAX_CONCURRENT_REQUESTS);

    // Spawn the response writer task
    let writer_handle = tokio::spawn(async move {
        while let Some(msg) = msg_rx.recv().await {
            match msg {
                ConnectionMessage::Text(text) => {
                    if let Err(e) = write.send(Message::Text(text.into())).await {
                        error!("Failed to send response: {}", e);
                        break;
                    }
                }
                ConnectionMessage::Ping(data) => {
                    if let Err(e) = write.send(Message::Pong(data.into())).await {
                        error!("Failed to send pong: {}", e);
                        break;
                    }
                }
                ConnectionMessage::Close => {
                    let _ = write.close().await;
                    break;
                }
                ConnectionMessage::Error(_) => {
                    // These don't produce responses
                }
            }
        }
    });

    // Process messages from the client
    while let Some(msg) = read.next().await {
        match msg {
            Ok(Message::Text(text)) => {
                debug!("Received: {}", text);

                // Parse JSON-RPC request
                let request: std::result::Result<Request, _> = serde_json::from_str(&text);

                match request {
                    Ok(request) => {
                        let ctx = ctx.clone();
                        let msg_tx = msg_tx.clone();

                        // Handle request asynchronously
                        tokio::spawn(async move {
                            let response = handle_request(&ctx, request).await;

                            if let Some(response) = response {
                                let response_json = serde_json::to_string(&response).unwrap();
                                let _ = msg_tx.send(ConnectionMessage::Text(response_json)).await;
                            }
                        });
                    }
                    Err(e) => {
                        error!("Failed to parse request: {}", e);
                        let error_response = ResponseError::new(
                            None,
                            "PARSE_ERROR",
                            format!("Invalid JSON: {}", e),
                        );
                        let response_json = serde_json::to_string(&error_response).unwrap();
                        let _ = msg_tx.send(ConnectionMessage::Text(response_json)).await;
                    }
                }
            }
            Ok(Message::Close(_)) => {
                info!("Connection closed by client");
                let _ = msg_tx.send(ConnectionMessage::Close).await;
                break;
            }
            Ok(Message::Ping(data)) => {
                // Respond with Pong
                let _ = msg_tx.send(ConnectionMessage::Ping(data.to_vec())).await;
            }
            Ok(Message::Pong(_)) => {
                // Ignore pong
            }
            Ok(Message::Binary(_data)) => {
                warn!("Received binary data, ignoring");
            }
            Ok(Message::Frame(_)) => {
                // Ignore frame
            }
            Err(e) => {
                error!("WebSocket error: {}", e);
                let _ = msg_tx.send(ConnectionMessage::Error(())).await;
                break;
            }
        }
    }

    // Wait for writer to finish
    let _ = writer_handle.await;

    info!("Connection closed: {}", addr);
}

//! Session management

use parking_lot::RwLock;
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::sync::Arc;
use uuid::Uuid;

/// Session ID
pub type SessionId = String;

/// Session state
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Session {
    /// Unique session ID
    pub id: SessionId,
    /// Session label (e.g., "main", "discord:123")
    pub label: Option<String>,
    /// Session type
    pub kind: SessionKind,
    /// Creation timestamp
    pub created_at: chrono::DateTime<chrono::Utc>,
    /// Last activity timestamp
    pub last_active: chrono::DateTime<chrono::Utc>,
    /// Session metadata
    #[allow(dead_code)]
    pub metadata: HashMap<String, serde_json::Value>,
}

/// Session kind
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[allow(dead_code)]
pub enum SessionKind {
    /// Main session (direct chat)
    Main,
    /// Isolated session (sub-agent, etc.)
    Isolated,
    /// Channel session
    Channel { channel: String },
}

impl Session {
    pub fn new(kind: SessionKind) -> Self {
        let now = chrono::Utc::now();
        Self {
            id: Uuid::new_v4().to_string(),
            label: None,
            kind,
            created_at: now,
            last_active: now,
            metadata: HashMap::new(),
        }
    }

    pub fn main() -> Self {
        Self::new(SessionKind::Main)
    }

    #[allow(dead_code)]
    pub fn isolated() -> Self {
        Self::new(SessionKind::Isolated)
    }

    #[allow(dead_code)]
    pub fn channel(channel: impl Into<String>) -> Self {
        Self::new(SessionKind::Channel {
            channel: channel.into(),
        })
    }

    #[allow(dead_code)]
    pub fn with_label(mut self, label: impl Into<String>) -> Self {
        self.label = Some(label.into());
        self
    }

    #[allow(dead_code)]
    pub fn update_activity(&mut self) {
        self.last_active = chrono::Utc::now();
    }
}

/// Session manager
pub struct SessionManager {
    sessions: RwLock<HashMap<SessionId, Arc<RwLock<Session>>>>,
}

impl SessionManager {
    pub fn new() -> Self {
        Self {
            sessions: RwLock::new(HashMap::new()),
        }
    }

    /// Create a new session
    pub fn create(&self, session: Session) -> Arc<RwLock<Session>> {
        let session = Arc::new(RwLock::new(session));
        let id = session.read().id.clone();
        self.sessions.write().insert(id, session.clone());
        session
    }

    /// Get a session by ID
    #[allow(dead_code)]
    pub fn get(&self, id: &SessionId) -> Option<Arc<RwLock<Session>>> {
        self.sessions.read().get(id).cloned()
    }

    /// List all sessions
    pub fn list(&self) -> Vec<Arc<RwLock<Session>>> {
        self.sessions.read().values().cloned().collect()
    }

    /// Remove a session
    #[allow(dead_code)]
    pub fn remove(&self, id: &SessionId) -> Option<Arc<RwLock<Session>>> {
        self.sessions.write().remove(id)
    }

    /// Get or create main session
    pub fn get_or_create_main(&self) -> Arc<RwLock<Session>> {
        let sessions = self.sessions.read();

        // Find main session
        for session in sessions.values() {
            if session.read().kind == SessionKind::Main {
                return session.clone();
            }
        }
        drop(sessions);

        // Create main session if not found
        self.create(Session::main())
    }
}

impl Default for SessionManager {
    fn default() -> Self {
        Self::new()
    }
}

