//! Advanced session management

use crate::common::error::{Error, Result};
use crate::gateway::session::{Session, SessionId, SessionManager};
use parking_lot::RwLock;
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::sync::Arc;

/// Session tag
#[derive(Debug, Clone, Serialize, Deserialize)]
#[allow(dead_code)]
pub struct SessionTag {
    pub name: String,
    pub color: Option<String>,
}

/// Extended session info with tags
#[derive(Debug, Clone, Serialize, Deserialize)]
#[allow(dead_code)]
pub struct ExtendedSession {
    #[serde(flatten)]
    pub session: Session,
    pub tags: Vec<SessionTag>,
    pub priority: i32,
    pub pinned: bool,
}

#[allow(dead_code)]
impl ExtendedSession {
    pub fn from_session(session: Session) -> Self {
        Self {
            session,
            tags: Vec::new(),
            priority: 0,
            pinned: false,
        }
    }

    pub fn with_tags(mut self, tags: Vec<SessionTag>) -> Self {
        self.tags = tags;
        self
    }

    pub fn with_priority(mut self, priority: i32) -> Self {
        self.priority = priority;
        self
    }

    pub fn pinned(mut self) -> Self {
        self.pinned = true;
        self
    }
}

/// Advanced session manager
#[allow(dead_code)]
pub struct AdvancedSessionManager {
    inner: Arc<SessionManager>,
    extended: RwLock<HashMap<SessionId, ExtendedSession>>,
    tags: RwLock<HashMap<String, SessionTag>>,
}

#[allow(dead_code)]
impl AdvancedSessionManager {
    pub fn new(inner: Arc<SessionManager>) -> Self {
        Self {
            inner,
            extended: RwLock::new(HashMap::new()),
            tags: RwLock::new(HashMap::new()),
        }
    }

    /// Create a session with extended info
    pub fn create_extended(&self, session: Session, extended: ExtendedSession) -> Arc<RwLock<Session>> {
        let arc = self.inner.create(session);
        let id = arc.read().id.clone();
        self.extended.write().insert(id, extended);
        arc
    }

    /// Get extended session info
    pub fn get_extended(&self, id: &SessionId) -> Option<ExtendedSession> {
        self.extended.read().get(id).cloned()
    }

    /// Update session tags
    pub fn set_tags(&self, id: &SessionId, tags: Vec<SessionTag>) -> Result<()> {
        let mut extended = self.extended.write();
        if let Some(session) = extended.get_mut(id) {
            session.tags = tags;
            Ok(())
        } else {
            Err(Error::SessionNotFound(id.clone()))
        }
    }

    /// Add tag to session
    pub fn add_tag(&self, id: &SessionId, tag: SessionTag) -> Result<()> {
        let mut extended = self.extended.write();
        if let Some(session) = extended.get_mut(id) {
            if !session.tags.iter().any(|t| t.name == tag.name) {
                session.tags.push(tag);
            }
            Ok(())
        } else {
            Err(Error::SessionNotFound(id.clone()))
        }
    }

    /// Remove tag from session
    pub fn remove_tag(&self, id: &SessionId, tag_name: &str) -> Result<()> {
        let mut extended = self.extended.write();
        if let Some(session) = extended.get_mut(id) {
            session.tags.retain(|t| t.name != tag_name);
            Ok(())
        } else {
            Err(Error::SessionNotFound(id.clone()))
        }
    }

    /// Set session priority
    pub fn set_priority(&self, id: &SessionId, priority: i32) -> Result<()> {
        let mut extended = self.extended.write();
        if let Some(session) = extended.get_mut(id) {
            session.priority = priority;
            Ok(())
        } else {
            Err(Error::SessionNotFound(id.clone()))
        }
    }

    /// Pin/unpin session
    pub fn set_pinned(&self, id: &SessionId, pinned: bool) -> Result<()> {
        let mut extended = self.extended.write();
        if let Some(session) = extended.get_mut(id) {
            session.pinned = pinned;
            Ok(())
        } else {
            Err(Error::SessionNotFound(id.clone()))
        }
    }

    /// List all tags
    pub fn list_tags(&self) -> Vec<SessionTag> {
        self.tags.read().values().cloned().collect()
    }

    /// Register a tag
    pub fn register_tag(&self, tag: SessionTag) {
        self.tags.write().insert(tag.name.clone(), tag);
    }

    /// Find sessions by tag
    pub fn find_by_tag(&self, tag_name: &str) -> Vec<SessionId> {
        self.extended.read()
            .iter()
            .filter(|(_, ext)| ext.tags.iter().any(|t| t.name == tag_name))
            .map(|(id, _)| id.clone())
            .collect()
    }

    /// Get all sessions sorted by priority (pinned first, then by priority)
    pub fn list_sorted(&self) -> Vec<ExtendedSession> {
        let mut sessions: Vec<ExtendedSession> = self.extended.read().values().cloned().collect();
        sessions.sort_by(|a, b| {
            match (a.pinned, b.pinned) {
                (true, false) => std::cmp::Ordering::Less,
                (false, true) => std::cmp::Ordering::Greater,
                _ => b.priority.cmp(&a.priority),
            }
        });
        sessions
    }

    /// Export session to JSON
    pub fn export_session(&self, id: &SessionId) -> Result<serde_json::Value> {
        let extended = self.extended.read();
        if let Some(session) = extended.get(id) {
            Ok(serde_json::to_value(session).map_err(|e| Error::Other(e.to_string()))?)
        } else {
            Err(Error::SessionNotFound(id.clone()))
        }
    }

    /// Import session from JSON
    pub fn import_session(&self, data: serde_json::Value) -> Result<SessionId> {
        let extended: ExtendedSession = serde_json::from_value(data)
            .map_err(|e| Error::Other(e.to_string()))?;

        let id = extended.session.id.clone();
        self.extended.write().insert(id.clone(), extended);
        Ok(id)
    }

    /// Forward to inner session manager
    pub fn inner(&self) -> &Arc<SessionManager> {
        &self.inner
    }
}

//! Message templates

use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use parking_lot::RwLock;

/// Message template
#[derive(Debug, Clone, Serialize, Deserialize)]
#[allow(dead_code)]
pub struct MessageTemplate {
    /// Template ID
    pub id: String,
    /// Template name
    pub name: String,
    /// Template content (supports {{variable}} placeholders)
    pub content: String,
    /// Description
    pub description: String,
    /// Tags for categorization
    pub tags: Vec<String>,
}

#[allow(dead_code)]
impl MessageTemplate {
    pub fn new(id: impl Into<String>, name: impl Into<String>, content: impl Into<String>) -> Self {
        Self {
            id: id.into(),
            name: name.into(),
            content: content.into(),
            description: String::new(),
            tags: Vec::new(),
        }
    }

    pub fn with_description(mut self, description: impl Into<String>) -> Self {
        self.description = description.into();
        self
    }

    pub fn with_tags(mut self, tags: Vec<String>) -> Self {
        self.tags = tags;
        self
    }

    /// Render the template with variables
    pub fn render(&self, variables: &HashMap<String, String>) -> String {
        let mut result = self.content.clone();
        for (key, value) in variables {
            let placeholder = format!("{{{{{}}}}}", key);
            result = result.replace(&placeholder, value);
        }
        result
    }
}

/// Template manager
#[allow(dead_code)]
pub struct TemplateManager {
    templates: RwLock<HashMap<String, MessageTemplate>>,
}

#[allow(dead_code)]
impl TemplateManager {
    pub fn new() -> Self {
        let manager = Self {
            templates: RwLock::new(HashMap::new()),
        };
        manager.init_builtin_templates();
        manager
    }

    fn init_builtin_templates(&self) {
        let builtin = vec![
            MessageTemplate::new("greeting", "Greeting", "Hello! {{name}}. How can I help you today?")
                .with_description("Default greeting message")
                .with_tags(vec!["greeting".to_string()]),
            MessageTemplate::new("farewell", "Farewell", "Goodbye, {{name}}! Have a great day!")
                .with_description("Default farewell message")
                .with_tags(vec!["greeting".to_string()]),
            MessageTemplate::new("error_generic", "Generic Error", "Something went wrong. Please try again later.")
                .with_description("Generic error message")
                .with_tags(vec!["error".to_string()]),
            MessageTemplate::new("error_permission", "Permission Error", "You don't have permission to perform this action.")
                .with_description("Permission denied message")
                .with_tags(vec!["error".to_string(), "auth".to_string()]),
            MessageTemplate::new("success", "Success", "Operation completed successfully!")
                .with_description("Success message")
                .with_tags(vec!["status".to_string()]),
            MessageTemplate::new("processing", "Processing", "I'm processing your request. Please wait...")
                .with_description("Processing message")
                .with_tags(vec!["status".to_string()]),
        ];

        let mut templates = self.templates.write();
        for template in builtin {
            templates.insert(template.id.clone(), template);
        }
    }

    /// Add a template
    pub fn add(&self, template: MessageTemplate) {
        self.templates.write().insert(template.id.clone(), template);
    }

    /// Remove a template
    pub fn remove(&self, id: &str) -> Option<MessageTemplate> {
        self.templates.write().remove(id)
    }

    /// Get a template by ID
    pub fn get(&self, id: &str) -> Option<MessageTemplate> {
        self.templates.read().get(id).cloned()
    }

    /// List all templates
    pub fn list(&self) -> Vec<MessageTemplate> {
        self.templates.read().values().cloned().collect()
    }

    /// Find templates by tag
    pub fn find_by_tag(&self, tag: &str) -> Vec<MessageTemplate> {
        self.templates.read()
            .values()
            .filter(|t| t.tags.contains(&tag.to_string()))
            .cloned()
            .collect()
    }

    /// Render a template
    pub fn render(&self, id: &str, variables: &HashMap<String, String>) -> Option<String> {
        self.templates.read()
            .get(id)
            .map(|t| t.render(variables))
    }
}

impl Default for TemplateManager {
    fn default() -> Self {
        Self::new()
    }
}

